            JsonSerializer.Serialize(writer, solicRecCompleta.Destinatario, jsonSerializerOptions);
            var statusRawValue = SolicRecCompleta.StatusEnumToJsonValue(solicRecCompleta.Status);
            writer.WriteString("status", statusRawValue);
            writer.WritePropertyName("atualizacao");
            JsonSerializer.Serialize(writer, solicRecCompleta.Atualizacao, jsonSerializerOptions);
            if (solicRecCompleta.RecPayloadOption.IsSet)
            {
                writer.WritePropertyName("recPayload");
                JsonSerializer.Serialize(writer, solicRecCompleta.RecPayload, jsonSerializerOptions);
            }
        }
    }
}
